    { title: "Acciones", desc: "Las cartas de Acción atacan al siguiente jugador, obligándolo a robar." },
    { title: "Reacciones", desc: "Si te atacan, usa una Reacción (como el Espejo Negro) para defenderte." },
    { title: "Rituales", desc: "Gasta tus Sombras para invocar Rituales poderosos. (Toca para lanzar)" },
    { title: "El Eclipse", desc: "Cuando te quede una sola carta, debes gritar ¡ECLIPSE! o serás penalizado." }
  ];

  useEffect(() => {
    if (step === 4) {
      setReactionTimer(3);
      const interval = setInterval(() => {
        setReactionTimer((prev) => {
          if (prev <= 1) {
            clearInterval(interval);
            setStep(5);
            return 0;
          }
          return prev - 1;
        });
