            <motion.div key="step0" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="flex flex-col items-center gap-8 text-center max-w-lg">
              <PlayingCard suit="blood" rank="A" className="scale-125 mb-8" />
