import {
  type ActionCard,
  type ActionKind,
  type Card,
  type NormalCard,
  type ReactionCard,
  type ReactionKind,
  type RitualCard,
  type RitualKind,
  type Suit,
} from "./types.js";

const SUITS: Suit[] = ["Ash", "Blood", "Bone", "Mist"];
const ACTIONS: ActionKind[] = ["Slash", "MistSkip", "GraveTurn", "Echo"];
const RITUAL_COSTS: Record<RitualKind, number> = {
  ColdHands: 2,
  ShadowSteal: 2,
  Duel: 3,
  Blackout: 4,
};
const REACTION_COSTS: Record<ReactionKind, number> = {
  BlackMirror: 1,
  Redirect: 1,
};

let nextId = 1;

function makeId(prefix: string): string {
  nextId += 1;
  return `${prefix}_${nextId}`;
}

export function resetCardIdCounter(): void {
  nextId = 1;
}

export function createNormalCard(suit: Suit, rank: number): NormalCard {
  return {
    id: makeId("n"),
    kind: "normal",
    suit,
    rank,
  };
}

export function createActionCard(action: ActionKind): ActionCard {
  return {
    id: makeId("a"),
    kind: "action",
    action,
  };
}

export function createRitualCard(ritual: RitualKind): RitualCard {
  return {
    id: makeId("r"),
    kind: "ritual",
    ritual,
    cost: RITUAL_COSTS[ritual],
  };
}

export function createReactionCard(reaction: ReactionKind): ReactionCard {
  return {
    id: makeId("rx"),
    kind: "reaction",
    reaction,
    cost: REACTION_COSTS[reaction],
  };
}

export function createStandardDeck(): Card[] {
  resetCardIdCounter();
  const deck: Card[] = [];

  for (const suit of SUITS) {
    for (let rank = 0; rank <= 9; rank += 1) {
      deck.push(createNormalCard(suit, rank));
      if (rank !== 0) {
        deck.push(createNormalCard(suit, rank));
      }
    }
  }

  for (const action of ACTIONS) {
    deck.push(createActionCard(action));
    deck.push(createActionCard(action));
    deck.push(createActionCard(action));
  }

  const rituals: RitualKind[] = ["ColdHands", "ShadowSteal", "Duel", "Blackout"];
  for (const ritual of rituals) {
    deck.push(createRitualCard(ritual));
    deck.push(createRitualCard(ritual));
  }

  deck.push(createReactionCard("BlackMirror"));
  deck.push(createReactionCard("BlackMirror"));
  deck.push(createReactionCard("Redirect"));
  deck.push(createReactionCard("Redirect"));

  return deck;
}

export function cardPower(card: Card): number {
  if (card.kind === "normal") {
    return card.rank;
  }
  if (card.kind === "action") {
    return 10;
  }
  if (card.kind === "reaction") {
    return 9;
  }
  return 11;
}

export function isPlayableOnTop(card: Card, topCard: Card | null): boolean {
  if (!topCard) {
    return true;
  }
  if (card.kind === "normal" && topCard.kind === "normal") {
    return card.suit === topCard.suit || card.rank === topCard.rank;
  }
  if (card.kind === "normal") {
    return true;
  }
  if (card.kind === "action") {
    return true;
  }
  if (card.kind === "ritual") {
    return true;
  }
  return false;
}

export function bucketCount(count: number): "few" | "medium" | "many" {
  if (count <= 2) {
    return "few";
  }
  if (count <= 5) {
    return "medium";
  }
  return "many";
}
