import { isPlayableOnTop } from "./cards.js";
import { SeededRng } from "./rng.js";
import type { Card, Difficulty, Personality, PlayerState, Suit } from "./types.js";

export interface BotContext {
  self: PlayerState;
  opponents: PlayerState[];
  topDiscard: Card | null;
}

export type BotMove =
  | { type: "eclipseCall" }
  | { type: "play"; cardId: string; targetId?: string; blackoutSuit?: Suit }
  | { type: "draw" };

function playableCards(context: BotContext): Card[] {
  return context.self.hand.filter((card) => {
    if (card.kind === "ritual") {
      return context.self.shadow >= card.cost;
    }
    if (card.kind === "reaction") {
      return false;
    }
    return isPlayableOnTop(card, context.topDiscard);
  });
}

function chooseTarget(personality: Personality, opponents: PlayerState[], rng: SeededRng): PlayerState | undefined {
  if (opponents.length === 0) {
    return undefined;
  }

  if (personality === "Cruel") {
    return [...opponents].sort((a, b) => a.hand.length - b.hand.length)[0];
  }

  if (personality === "Coward") {
    return [...opponents].sort((a, b) => b.hand.length - a.hand.length)[0];
  }

  return rng.pick(opponents);
}

function cardScore(card: Card, difficulty: Difficulty, personality: Personality, shadow: number): number {
  let score = 0;

  if (card.kind === "normal") {
    score += card.rank;
  }

  if (card.kind === "action") {
    score += 12;
    if (card.action === "Slash" && personality === "Cruel") {
      score += 3;
    }
    if (card.action === "MistSkip") {
      score += 2;
    }
  }

  if (card.kind === "ritual") {
    score += 14;
    if (card.ritual === "Blackout") {
      score += personality === "Coward" ? -4 : 2;
    }
    if (difficulty === "Oracle") {
      score += 3;
    }
    if (difficulty === "Minion" && shadow < card.cost + 1) {
      score -= 4;
    }
  }

  if (difficulty === "Adept") {
    score += 1;
  }

  if (difficulty === "Oracle") {
    score += 2;
  }

  return score;
}

export function chooseBotMove(context: BotContext, rng: SeededRng): BotMove {
  const { self } = context;

  if (self.mustCallEclipse && !self.hasCalledEclipse) {
    if (self.personality !== "Chaotic" || rng.next() > 0.4) {
      return { type: "eclipseCall" };
    }
  }

  const cards = playableCards(context);
  if (cards.length === 0) {
    return { type: "draw" };
  }

  const scored = cards
    .map((card) => ({ card, score: cardScore(card, self.difficulty ?? "Minion", self.personality ?? "Chaotic", self.shadow) }))
    .sort((a, b) => b.score - a.score);

  let selected = scored[0].card;

  if ((self.difficulty ?? "Minion") === "Minion" && rng.next() < 0.35) {
    selected = rng.pick(cards);
  }

  if ((self.personality ?? "Chaotic") === "Chaotic" && rng.next() < 0.45) {
    selected = rng.pick(cards);
  }

  const target = chooseTarget(self.personality ?? "Chaotic", context.opponents, rng);
  const move: BotMove = {
    type: "play",
    cardId: selected.id,
  };

  if (selected.kind === "action" || (selected.kind === "ritual" && selected.ritual !== "Blackout")) {
    move.targetId = target?.id;
  }

  if (selected.kind === "ritual" && selected.ritual === "Blackout") {
    const suits: Suit[] = ["Ash", "Blood", "Bone", "Mist"];
    move.blackoutSuit = suits[rng.nextInt(suits.length)];
  }

  return move;
}
EOF"}

