function randomCode(seed: number): string {
  const letters = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  const rng = new SeededRng(seed);
  let value = "";
  for (let i = 0; i < 4; i += 1) {
    value += letters[rng.nextInt(letters.length)];
  }
  return value;
}

function createBotName(index: number): string {
