      clearTimeout(timer);
    }
    this.timers.clear();
    this.clearReactionWindow();
  }

  private emit(type: EngineEvent["type"], payload?: Record<string, unknown>): void {
    this.onEmit?.({ type, payload });
  }

  private schedule(fn: () => void, delayMs: number): void {
    const timer = setTimeout(() => {
      this.timers.delete(timer);
      fn();
    }, delayMs);
    this.timers.add(timer);
  }

  private emitStateChanged(): void {
    this.emit("state_changed", {
      roomId: this.roomId,
      code: this.code,
      roomType: this.roomType,
    });
  }

  private createPlayer(reg: PlayerRegistration): PlayerState {
    return {
      id: reg.id,
      name: reg.name,
      isBot: reg.isBot ?? false,
      difficulty: reg.difficulty,
      personality: reg.personality,
      hand: [],
      shadow: 0,
      ready: false,
      hasCalledEclipse: false,
      mustCallEclipse: false,
      pendingEclipsePenalty: false,
      reactionsBlockedRounds: 0,
      socketId: reg.socketId,
      connected: reg.connected ?? true,
    };
  }

  addPlayer(reg: PlayerRegistration): PlayerState {
    const existing = this.players.find((player) => player.id === reg.id);
    if (existing) {
      existing.socketId = reg.socketId ?? existing.socketId;
      existing.connected = reg.connected ?? true;
      existing.name = reg.name || existing.name;
      return existing;
    }

    if (this.roomType === "tutorial" && this.players.some((player) => !player.isBot)) {
      throw new Error("Tutorial room already has a user");
    }

    if (this.started && this.roomType !== "tutorial") {
      throw new Error("Room already started");
    }

    const player = this.createPlayer(reg);
    this.players.push(player);
    this.emit("player_joined", {
      roomId: this.roomId,
      playerId: player.id,
      name: player.name,
      isBot: player.isBot,
    });
    this.emitStateChanged();
    return player;
  }

  addBot(options: { difficulty: Difficulty; personality: Personality; name?: string }): PlayerState {
    if (this.roomType === "tutorial") {
      throw new Error("Tutorial room uses scripted bots");
    }

    if (this.started) {
      throw new Error("Cannot add bots after start");
    }

    const botId = `bot_${Date.now()}_${this.rng.nextInt(100000)}`;
    const bot = this.createPlayer({
      id: botId,
      name: options.name ?? createBotName(this.players.length),
      isBot: true,
      difficulty: options.difficulty,
      personality: options.personality,
      connected: true,
    });
    bot.ready = true;
    this.players.push(bot);
    this.emit("player_joined", {
      roomId: this.roomId,
      playerId: bot.id,
      name: bot.name,
      isBot: true,
      difficulty: bot.difficulty,
      personality: bot.personality,
    });
    this.emitStateChanged();
    return bot;
  }

  removePlayer(playerId: string): void {
    const index = this.players.findIndex((player) => player.id === playerId);
    if (index === -1) {
      return;
    }

    const [removed] = this.players.splice(index, 1);
    this.emit("player_left", {
      roomId: this.roomId,
      playerId: removed.id,
      name: removed.name,
    });

    if (this.players.length === 0) {
      this.destroy();
      return;
    }

    if (index < this.turnIndex) {
      this.turnIndex -= 1;
    }

    if (this.turnIndex >= this.players.length) {
      this.turnIndex = 0;
    }

    this.emitStateChanged();
  }

  setPlayerSocket(playerId: string, socketId: string): void {
    const player = this.getPlayer(playerId);
    if (!player) {
      return;
    }
    player.socketId = socketId;
    player.connected = true;
  }

  setPlayerConnected(playerId: string, connected: boolean): void {
    const player = this.getPlayer(playerId);
    if (!player) {
      return;
    }
    player.connected = connected;
  }

  setReady(playerId: string, ready: boolean): void {
    const player = this.getPlayer(playerId);
    if (!player) {
      throw new Error("Player not found");
    }

    player.ready = ready;
    this.emitStateChanged();
  }

  canStart(): boolean {
    if (this.roomType === "tutorial") {
      return this.players.filter((player) => !player.isBot).length === 1;
    }

    if (this.players.length < 3) {
      return false;
    }

    return this.players.every((player) => player.isBot || player.ready);
  }

  start(): void {
    if (this.started) {
      throw new Error("Room already started");
    }

    if (!this.canStart()) {
      throw new Error("Not enough ready players to start");
    }

    this.direction = 1;
    this.turnIndex = 0;
    this.turnNumber = 1;
    this.lastAction = null;
    this.skipNext = false;
    this.blackout = undefined;
    this.winner = undefined;

    if (this.roomType === "tutorial") {
      this.setupTutorialState();
    } else {
      this.setupMultiplayerState();
    }

    this.started = true;

    const current = this.getCurrentPlayer();
    this.emit("room_started", {
      roomId: this.roomId,
      roomType: this.roomType,
      currentPlayerId: current?.id ?? null,
    });

    if (current) {
      this.emit("turn_started", {
        roomId: this.roomId,
        playerId: current.id,
        turnNumber: this.turnNumber,
      });
    }

    if (this.roomType === "multiplayer") {
      this.scheduleBotLoop();
    } else {
      this.emitTutorialStep();
    }

    this.emitStateChanged();
  }

  private setupMultiplayerState(): void {
    const deck = this.rng.shuffle(createStandardDeck());
    this.drawPile = deck;
    this.discardPile = [];

    for (const player of this.players) {
      player.hand = [];
      player.shadow = 0;
      player.hasCalledEclipse = false;
      player.mustCallEclipse = false;
      player.pendingEclipsePenalty = false;
      player.reactionsBlockedRounds = 0;
    }

    for (let i = 0; i < 5; i += 1) {
      for (const player of this.players) {
        const drawn = this.drawPile.shift();
        if (drawn) {
          player.hand.push(drawn);
        }
      }
    }

    let top: Card | undefined;
    while (this.drawPile.length > 0) {
      const candidate = this.drawPile.shift();
      if (!candidate) {
        break;
      }
      if (candidate.kind === "normal") {
        top = candidate;
        break;
      }
      this.drawPile.push(candidate);
    }

    if (!top) {
      top = {
        id: `fallback_${Date.now()}`,
        kind: "normal",
        suit: "Ash",
        rank: 0,
      };
    }

    this.discardPile = [top];
  }

  private setupTutorialState(): void {
    const user = this.players.find((player) => !player.isBot);
    if (!user) {
      throw new Error("Tutorial requires one user");
    }

    const scriptedPlayers = createTutorialPlayers(user.id, user.name);
    const scriptedUser = scriptedPlayers.find((player) => player.id === user.id);
    if (scriptedUser) {
      scriptedUser.socketId = user.socketId;
      scriptedUser.connected = user.connected;
      scriptedUser.ready = true;
    }

    this.players = scriptedPlayers;
    this.drawPile = createTutorialDrawPile();
    this.discardPile = [cloneCard(TUTORIAL_INITIAL_DISCARD)];
    this.turnIndex = this.players.findIndex((player) => player.id === user.id);
    this.tutorialState = {
      userId: user.id,
      currentStepIndex: 0,
      completed: false,
      skipped: false,
    };
  }

  restartTutorial(userName?: string): void {
    if (this.roomType !== "tutorial") {
      throw new Error("restartTutorial is only available for tutorial rooms");
    }

    const user = this.players.find((player) => !player.isBot);
    if (!user) {
      throw new Error("Tutorial user not found");
    }

    const preservedSocketId = user.socketId;
    const preservedConnection = user.connected;
    const preservedName = userName ?? user.name;

    this.players = [
      {
        ...user,
        name: preservedName,
        hand: [],
      },
    ];

    this.started = false;
    this.winner = undefined;
    this.clearReactionWindow();
    this.setupTutorialState();

    const tutorialUser = this.players.find((player) => !player.isBot);
    if (tutorialUser) {
      tutorialUser.socketId = preservedSocketId;
      tutorialUser.connected = preservedConnection;
    }

    this.started = true;
    this.turnNumber = 1;
    this.emit("room_started", {
      roomId: this.roomId,
      roomType: this.roomType,
      currentPlayerId: tutorialUser?.id ?? null,
      restarted: true,
    });
    this.emit("turn_started", {
      roomId: this.roomId,
      playerId: tutorialUser?.id ?? null,
      turnNumber: this.turnNumber,
    });
    this.emitTutorialStep();
    this.emitStateChanged();
  }

  skipTutorial(userId: string): void {
    if (this.roomType !== "tutorial") {
      throw new Error("skipTutorial is only available for tutorial rooms");
    }

    if (!this.tutorialState || this.tutorialState.userId !== userId) {
      throw new Error("Only tutorial user can skip");
    }

    this.tutorialState.skipped = true;
    this.emit("tutorial_skipped", {
      roomId: this.roomId,
      userId,
    });
    this.emitStateChanged();
  }

  getPlayer(playerId: string): PlayerState | undefined {
    return this.players.find((player) => player.id === playerId);
  }

  getCurrentPlayer(): PlayerState | undefined {
    if (this.players.length === 0) {
      return undefined;
    }
    return this.players[this.turnIndex];
  }

  eclipseCall(playerId: string): void {
    const player = this.getPlayer(playerId);
    if (!player) {
      throw new Error("Player not found");
    }

    if (!player.mustCallEclipse) {
      throw new Error("Eclipse call not required right now");
    }

    if (this.roomType === "tutorial" && !this.ensureTutorialActionAllowed(playerId, "eclipseCall")) {
      throw new Error("Action not allowed in current tutorial step");
    }

    player.hasCalledEclipse = true;
    player.pendingEclipsePenalty = true;
    this.emit("eclipse_called", {
      roomId: this.roomId,
      playerId,
    });

    if (this.roomType === "tutorial" && this.tutorialState) {
      this.tutorialState.completed = true;
      this.emit("tutorial_completed", {
        roomId: this.roomId,
        userId: playerId,
      });
    }

    this.emitStateChanged();
  }

  drawForPlayer(playerId: string, count = 1, endTurn = false): void {
    const player = this.getPlayer(playerId);
    if (!player) {
      throw new Error("Player not found");
    }

    if (this.reactionWindow) {
      throw new Error("Cannot draw while reaction window is open");
    }

    if (this.getCurrentPlayer()?.id !== playerId) {
      throw new Error("Not your turn");
    }

    this.drawCards(player, count);
    if (endTurn) {
      this.endTurn(playerId);
    }

    this.emitStateChanged();
  }

  playCard(input: { playerId: string; cardId: string; targetId?: string; blackoutSuit?: Suit }): void {
    if (!this.started) {
      throw new Error("Room has not started");
    }

    if (this.winner) {
      throw new Error("Game already finished");
    }

    if (this.reactionWindow) {
      throw new Error("Resolve reaction window first");
    }

    const player = this.getPlayer(input.playerId);
    if (!player) {
      throw new Error("Player not found");
    }

    if (this.getCurrentPlayer()?.id !== player.id) {
      throw new Error("Not your turn");
    }

    if (this.roomType === "tutorial" && !player.isBot) {
      this.handleTutorialPlay(input.playerId, input.cardId, input.targetId);
      return;
    }

    const cardIndex = player.hand.findIndex((card) => card.id === input.cardId);
    if (cardIndex === -1) {
      throw new Error("Card not in hand");
    }

    const card = player.hand[cardIndex];
    const topDiscard = this.discardPile[this.discardPile.length - 1] ?? null;

    if (card.kind === "reaction") {
      throw new Error("Reaction cards are out-of-turn only");
    }

    if (card.kind === "ritual" && player.shadow < card.cost) {
      throw new Error("Not enough shadow for ritual");
    }

    if ((card.kind === "normal" || card.kind === "action") && !isPlayableOnTop(card, topDiscard)) {
      throw new Error("Card is not playable on current discard");
    }

    player.hand.splice(cardIndex, 1);
    this.discardPile.push(card);

    if (card.kind === "normal" || card.kind === "action") {
      player.shadow = Math.min(6, player.shadow + 1);
      this.emit("shadow_changed", {
        roomId: this.roomId,
        playerId: player.id,
        shadow: player.shadow,
      });
    }

    if (card.kind === "ritual") {
      player.shadow -= card.cost;
      this.emit("shadow_changed", {
        roomId: this.roomId,
        playerId: player.id,
        shadow: player.shadow,
      });
    }

    this.emit("card_played", {
      roomId: this.roomId,
      playerId: player.id,
      card,
      targetId: input.targetId,
    });

    this.handleEclipseTrackingAfterPlay(player, card);
    if (this.winner) {
      this.emitStateChanged();
      return;
    }

    if (card.kind === "action") {
      this.resolveActionCard(card.action, player.id, input.targetId);
      this.emitStateChanged();
      return;
    }

    if (card.kind === "ritual") {
      this.resolveRitualCard(card.ritual, player.id, input.targetId, input.blackoutSuit);
      this.emitStateChanged();
      return;
    }

    this.endTurn(player.id);
    this.emitStateChanged();
  }

  useReaction(input: ReactionInput): void {
    if (!this.reactionWindow) {
      throw new Error("No reaction window open");
    }

    const effect = this.reactionWindow.effect;
    if (effect.targetId !== input.playerId) {
      throw new Error("Only targeted player can react");
    }

    if (this.roomType === "tutorial" && !this.ensureTutorialActionAllowed(input.playerId, `reaction:${input.cardId}`)) {
      throw new Error("Action not allowed in current tutorial step");
    }

    const player = this.getPlayer(input.playerId);
    if (!player) {
      throw new Error("Player not found");
    }

    const cardIndex = player.hand.findIndex((card) => card.id === input.cardId);
    if (cardIndex === -1) {
      throw new Error("Reaction card not in hand");
    }

    const card = player.hand[cardIndex];
    if (card.kind !== "reaction") {
      throw new Error("Selected card is not a reaction");
    }

    if (player.shadow < card.cost) {
      throw new Error("Not enough shadow to react");
    }

    player.hand.splice(cardIndex, 1);
    player.shadow -= card.cost;

    this.emit("reaction_used", {
      roomId: this.roomId,
      playerId: player.id,
      reaction: card.reaction,
      effectId: effect.id,
    });

    this.emit("shadow_changed", {
      roomId: this.roomId,
      playerId: player.id,
      shadow: player.shadow,
    });

    this.clearReactionWindow("reacted");

    if (card.reaction === "BlackMirror") {
      this.emit("effect_resolved", {
        roomId: this.roomId,
        effectId: effect.id,
        cancelled: true,
        by: "BlackMirror",
      });

      if (this.roomType === "tutorial") {
        this.handleTutorialAfterReaction();
      } else {
        this.endTurn(effect.sourceId);
      }

      this.emitStateChanged();
      return;
    }

    const redirectTarget = input.redirectTargetId;
    if (!redirectTarget) {
      throw new Error("Redirect requires redirectTargetId");
    }

    const redirectPlayer = this.getPlayer(redirectTarget);
    if (!redirectPlayer) {
      throw new Error("Redirect target not found");
    }

    const redirectedEffect: PendingEffect = {
      ...effect,
      targetId: redirectTarget,
    };

    this.emit("effect_resolved", {
      roomId: this.roomId,
      effectId: effect.id,
      redirectedTo: redirectTarget,
      by: "Redirect",
    });

    this.resolvePendingEffect(redirectedEffect);

    if (this.roomType === "tutorial") {
      this.handleTutorialAfterReaction();
    } else {
      this.endTurn(effect.sourceId);
    }

    this.emitStateChanged();
  }

  private handleEclipseTrackingAfterPlay(player: PlayerState, playedCard: Card): void {
    if (player.hand.length === 1) {
      player.mustCallEclipse = true;
      player.pendingEclipsePenalty = true;
      player.hasCalledEclipse = false;
    }

    if (player.hand.length === 0) {
      this.winner = {
        playerId: player.id,
        victoryType: playedCard.kind === "ritual" ? "Ascension" : "Eclipse",
      };
      this.emit("winner_declared", {
        roomId: this.roomId,
        ...this.winner,
      });
    }
  }

  private resolveActionCard(action: "Slash" | "MistSkip" | "GraveTurn" | "Echo", sourceId: string, explicitTargetId?: string): void {
    let actionToResolve = action;

    if (action === "Echo") {
      if (!this.lastAction) {
        this.emit("effect_resolved", {
          roomId: this.roomId,
          action,
          result: "noop",
        });
        this.endTurn(sourceId);
        return;
      }
      actionToResolve = this.lastAction;
    }

    if (actionToResolve === "Slash") {
      const target = explicitTargetId ? this.getPlayer(explicitTargetId) : this.getNextPlayer(this.turnIndex);
      if (!target) {
        this.endTurn(sourceId);
        return;
      }

      const effect: PendingEffect = {
        id: `effect_${Date.now()}_${this.rng.nextInt(10000)}`,
        sourceId,
        targetId: target.id,
        effectType: "draw",
        amount: 1,
      };

      if (!this.openReactionWindow(effect)) {
        this.resolvePendingEffect(effect);
        this.endTurn(sourceId);
      }

      this.lastAction = "Slash";
      return;
    }

    if (actionToResolve === "MistSkip") {
      this.skipNext = true;
      this.emit("effect_resolved", {
        roomId: this.roomId,
        action: "MistSkip",
      });
      this.lastAction = "MistSkip";
      this.endTurn(sourceId);
      return;
    }

    this.direction = this.direction === 1 ? -1 : 1;
    this.emit("effect_resolved", {
      roomId: this.roomId,
      action: "GraveTurn",
      direction: this.direction,
    });
    this.lastAction = "GraveTurn";
    this.endTurn(sourceId);
  }

  private resolveRitualCard(
    ritual: "ColdHands" | "ShadowSteal" | "Duel" | "Blackout",
    sourceId: string,
    targetId?: string,
    blackoutSuit?: Suit,
  ): void {
    if (ritual === "Blackout") {
      const suit = blackoutSuit ?? "Mist";
      this.blackout = {
        suit,
        roundsLeft: this.players.length,
      };
      this.emit("effect_resolved", {
        roomId: this.roomId,
        ritual,
        suit,
      });
      this.endTurn(sourceId);
      return;
    }

    if (!targetId) {
      throw new Error(`Ritual ${ritual} requires targetId`);
    }

    const target = this.getPlayer(targetId);
    if (!target) {
      throw new Error("Target not found");
    }

    let effect: PendingEffect;

    if (ritual === "ColdHands") {
      effect = {
        id: `effect_${Date.now()}_${this.rng.nextInt(10000)}`,
        sourceId,
        targetId,
        effectType: "coldHands",
      };
    } else if (ritual === "ShadowSteal") {
      effect = {
        id: `effect_${Date.now()}_${this.rng.nextInt(10000)}`,
        sourceId,
        targetId,
        effectType: "shadowSteal",
      };
    } else {
      effect = {
        id: `effect_${Date.now()}_${this.rng.nextInt(10000)}`,
        sourceId,
        targetId,
        effectType: "duel",
      };
    }

    if (!this.openReactionWindow(effect)) {
      this.resolvePendingEffect(effect);
      this.endTurn(sourceId);
    }
  }

  private openReactionWindow(effect: PendingEffect): boolean {
    const target = this.getPlayer(effect.targetId);
    if (!target) {
      return false;
    }

    if (target.reactionsBlockedRounds > 0) {
      return false;
    }

    const reactionCard = target.hand.find((card) => card.kind === "reaction" && target.shadow >= card.cost);
    if (!reactionCard) {
      return false;
    }

    const timeoutMs = this.roomType === "tutorial" ? this.tutorialReactionTimeoutMs : this.multiplayerReactionTimeoutMs;
    const expiresAt = Date.now() + timeoutMs;

    this.reactionWindow = {
      effect,
      timeoutMs,
      expiresAt,
    };

    this.emit("reaction_window_opened", {
      roomId: this.roomId,
      effectId: effect.id,
      sourceId: effect.sourceId,
      targetId: effect.targetId,
      effectType: effect.effectType,
      timeoutMs,
    });

    this.schedule(() => {
      if (!this.reactionWindow || this.reactionWindow.effect.id !== effect.id) {
        return;
      }

      this.clearReactionWindow("timeout");
      this.resolvePendingEffect(effect);

      if (this.roomType === "tutorial") {
        this.handleTutorialAfterReaction();
      } else {
        this.endTurn(effect.sourceId);
      }

      this.emitStateChanged();
    }, timeoutMs);

    return true;
  }

  private clearReactionWindow(reason: "timeout" | "reacted" | "resolved" = "resolved"): void {
    if (!this.reactionWindow) {
      return;
    }

    const effectId = this.reactionWindow.effect.id;
    this.reactionWindow = undefined;

    this.emit("reaction_window_closed", {
      roomId: this.roomId,
      effectId,
      reason,
    });
  }

  private resolvePendingEffect(effect: PendingEffect): void {
    const source = this.getPlayer(effect.sourceId);
    const target = this.getPlayer(effect.targetId);

    if (!source || !target) {
      return;
    }

    if (effect.effectType === "draw") {
      this.drawCards(target, effect.amount ?? 1);
      this.emit("effect_resolved", {
        roomId: this.roomId,
        effectId: effect.id,
        effectType: effect.effectType,
        targetId: target.id,
        amount: effect.amount ?? 1,
      });
      return;
    }

    if (effect.effectType === "coldHands") {
      target.reactionsBlockedRounds = Math.max(target.reactionsBlockedRounds, 1);
      this.emit("effect_resolved", {
        roomId: this.roomId,
        effectId: effect.id,
        effectType: effect.effectType,
        targetId: target.id,
      });
      return;
    }

    if (effect.effectType === "shadowSteal") {
      if (target.hand.length > 0) {
        const index = this.rng.nextInt(target.hand.length);
        const [stolen] = target.hand.splice(index, 1);
        source.hand.push(stolen);

        this.emit("effect_resolved", {
          roomId: this.roomId,
          effectId: effect.id,
          effectType: effect.effectType,
          targetId: target.id,
          sourceId: source.id,
          stolenCardId: stolen.id,
        });
      } else {
        this.emit("effect_resolved", {
          roomId: this.roomId,
          effectId: effect.id,
          effectType: effect.effectType,
          targetId: target.id,
          sourceId: source.id,
          stolenCardId: null,
        });
      }
      return;
    }

    const sourceCard = source.hand.length > 0 ? source.hand[this.rng.nextInt(source.hand.length)] : null;
    const targetCard = target.hand.length > 0 ? target.hand[this.rng.nextInt(target.hand.length)] : null;

    const sourcePower = sourceCard ? cardPower(sourceCard) : -1;
    const targetPower = targetCard ? cardPower(targetCard) : -1;

    if (sourcePower < targetPower) {
      this.drawCards(source, 3);
      this.emit("effect_resolved", {
        roomId: this.roomId,
        effectId: effect.id,
        effectType: effect.effectType,
        loserId: source.id,
        winnerId: target.id,
      });
      return;
    }

    if (targetPower < sourcePower) {
      this.drawCards(target, 3);
      this.emit("effect_resolved", {
        roomId: this.roomId,
        effectId: effect.id,
        effectType: effect.effectType,
        loserId: target.id,
        winnerId: source.id,
      });
      return;
    }

    this.emit("effect_resolved", {
      roomId: this.roomId,
      effectId: effect.id,
      effectType: effect.effectType,
      loserId: null,
      winnerId: null,
    });
  }

  private drawCards(player: PlayerState, amount: number): void {
    const drawnCards: Card[] = [];

    for (let i = 0; i < amount; i += 1) {
      if (this.drawPile.length === 0) {
        this.refillDrawPile();
      }

      const card = this.drawPile.shift();
      if (!card) {
        break;
      }

      player.hand.push(card);
      drawnCards.push(card);
    }

    if (drawnCards.length > 0) {
      this.emit("cards_drawn", {
        roomId: this.roomId,
        playerId: player.id,
        amount: drawnCards.length,
        cardIds: drawnCards.map((card) => card.id),
      });
    }
  }

  private refillDrawPile(): void {
    if (this.discardPile.length <= 1) {
      return;
    }

    const top = this.discardPile[this.discardPile.length - 1];
    const rest = this.discardPile.slice(0, -1);
    this.drawPile = this.rng.shuffle(rest);
    this.discardPile = [top];
  }

  private endTurn(sourcePlayerId: string): void {
    if (this.winner) {
      return;
    }

    const current = this.getCurrentPlayer();
    if (!current || current.id !== sourcePlayerId) {
      return;
    }

    const previous = current;

    let nextIndex = this.findNextTurnIndex(this.turnIndex);
    if (this.skipNext) {
      const skipped = this.players[nextIndex];
      this.emit("effect_resolved", {
        roomId: this.roomId,
        action: "MistSkip",
        skippedPlayerId: skipped?.id,
      });
      nextIndex = this.findNextTurnIndex(nextIndex);
      this.skipNext = false;
    }

    this.turnIndex = nextIndex;
    this.turnNumber += 1;

    if (this.blackout) {
      this.blackout.roundsLeft -= 1;
      if (this.blackout.roundsLeft <= 0) {
        this.blackout = undefined;
      }
    }

    this.resolveEclipsePenalty(previous);

    const next = this.getCurrentPlayer();
    if (next && next.reactionsBlockedRounds > 0) {
      next.reactionsBlockedRounds -= 1;
    }

    this.emit("turn_started", {
      roomId: this.roomId,
      playerId: next?.id ?? null,
      turnNumber: this.turnNumber,
    });

    if (this.roomType === "multiplayer") {
      this.scheduleBotLoop();
    }
  }

  private resolveEclipsePenalty(previous: PlayerState): void {
    if (!previous.pendingEclipsePenalty) {
      return;
    }

    if (!previous.hasCalledEclipse) {
      this.drawCards(previous, 2);
      this.emit("eclipse_penalty", {
        roomId: this.roomId,
        playerId: previous.id,
        amount: 2,
      });
    }

    previous.pendingEclipsePenalty = false;
    previous.mustCallEclipse = false;
    previous.hasCalledEclipse = false;
  }

  private findNextTurnIndex(fromIndex: number): number {
    if (this.players.length === 0) {
      return 0;
    }

    let index = fromIndex;
    for (let i = 0; i < this.players.length; i += 1) {
      index = (index + this.direction + this.players.length) % this.players.length;
      const candidate = this.players[index];
      if (candidate) {
        return index;
      }
    }

    return fromIndex;
  }

  private getNextPlayer(fromIndex: number): PlayerState | undefined {
    if (this.players.length === 0) {
      return undefined;
    }
    const nextIndex = this.findNextTurnIndex(fromIndex);
    return this.players[nextIndex];
  }

  private scheduleBotLoop(): void {
    if (this.botLoopScheduled || this.roomType !== "multiplayer") {
      return;
    }

    this.botLoopScheduled = true;
    this.schedule(() => {
      this.botLoopScheduled = false;
      this.runBotsIfNeeded();
    }, this.botDelayMs);
  }

  private runBotsIfNeeded(): void {
    if (!this.started || this.winner || this.reactionWindow || this.roomType !== "multiplayer") {
      return;
    }

    let safety = 0;
    while (safety < 20) {
      const current = this.getCurrentPlayer();
      if (!current || !current.isBot) {
        break;
      }

      const opponents = this.players.filter((player) => player.id !== current.id);
      const move = chooseBotMove(
        {
          self: current,
          opponents,
          topDiscard: this.discardPile[this.discardPile.length - 1] ?? null,
        },
        this.rng,
      );

      if (move.type === "eclipseCall" && current.mustCallEclipse) {
        try {
          this.eclipseCall(current.id);
        } catch {
          // ignore invalid eclipse attempts by bot
        }
      }

      if (move.type === "draw") {
        this.drawCards(current, 1);
        this.endTurn(current.id);
        safety += 1;
        continue;
      }

      if (move.type === "play") {
        const hasCard = current.hand.some((card) => card.id === move.cardId);
        if (!hasCard) {
          this.drawCards(current, 1);
          this.endTurn(current.id);
          safety += 1;
          continue;
        }

        try {
          this.playCard({
            playerId: current.id,
            cardId: move.cardId,
            targetId: move.targetId,
            blackoutSuit: move.blackoutSuit,
          });
        } catch {
          this.drawCards(current, 1);
          this.endTurn(current.id);
        }
      }

      safety += 1;

      if (this.reactionWindow || this.winner) {
        break;
      }
    }

    this.emitStateChanged();
  }

  private handleTutorialPlay(playerId: string, cardId: string, targetId?: string): void {
    if (!this.tutorialState) {
      throw new Error("Tutorial state not initialized");
    }

    if (!this.ensureTutorialActionAllowed(playerId, `playCard:${cardId}`)) {
      throw new Error("Action not allowed in current tutorial step");
    }

    const player = this.getPlayer(playerId);
    if (!player) {
      throw new Error("Player not found");
    }

    const cardIndex = player.hand.findIndex((card) => card.id === cardId);
    if (cardIndex === -1) {
      throw new Error("Card not in hand");
    }

    const card = player.hand[cardIndex];
    player.hand.splice(cardIndex, 1);
    this.discardPile.push(card);

    if (card.kind === "normal" || card.kind === "action") {
      player.shadow = Math.min(6, player.shadow + 1);
      this.emit("shadow_changed", {
        roomId: this.roomId,
        playerId,
        shadow: player.shadow,
      });
    }

    if (card.kind === "ritual") {
      if (player.shadow < card.cost) {
        throw new Error("Not enough shadow for ritual");
      }
      player.shadow -= card.cost;
      this.emit("shadow_changed", {
        roomId: this.roomId,
        playerId,
        shadow: player.shadow,
      });
    }

    this.emit("card_played", {
      roomId: this.roomId,
      playerId,
      card,
      targetId,
    });

    if (this.tutorialState.currentStepIndex === 0 && cardId === TUTORIAL_USER_CARD_BLOOD4) {
      this.setTutorialStep(1);
      this.schedule(() => this.playTutorialBotSlash(), this.botDelayMs);
      this.emitStateChanged();
      return;
    }

    if (this.tutorialState.currentStepIndex === 3 && cardId === TUTORIAL_USER_CARD_STEAL) {
      const target = this.getPlayer(targetId ?? TUTORIAL_BOT_2_ID);
      if (!target) {
        throw new Error("Tutorial target not found");
      }

      if (target.hand.length > 0) {
        const index = this.rng.nextInt(target.hand.length);
        const [stolen] = target.hand.splice(index, 1);
        player.hand.push(stolen);
      }

      this.emit("effect_resolved", {
        roomId: this.roomId,
        effectType: "shadowSteal",
        sourceId: player.id,
        targetId: target.id,
      });

      this.schedule(() => this.playTutorialBotForgetEclipse(), this.botDelayMs);
      this.emitStateChanged();
      return;
    }

    if (this.tutorialState.currentStepIndex === 5 && cardId === TUTORIAL_USER_CARD_BONE7) {
      this.handleEclipseTrackingAfterPlay(player, card);
      this.setTutorialStep(6);
      this.emitStateChanged();
      return;
    }

    throw new Error("Tutorial script mismatch");
  }

  private playTutorialBotSlash(): void {
    if (!this.tutorialState || this.tutorialState.completed || this.tutorialState.skipped) {
      return;
    }

    const bot = this.getPlayer(TUTORIAL_BOT_1_ID);
    const user = this.getPlayer(this.tutorialState.userId);
    if (!bot || !user) {
      return;
    }

    this.turnIndex = this.players.findIndex((player) => player.id === bot.id);

    const cardIndex = bot.hand.findIndex((card) => card.id === TUTORIAL_BOT1_CARD_SLASH);
    if (cardIndex === -1) {
      return;
    }

    const [card] = bot.hand.splice(cardIndex, 1);
    this.discardPile.push(card);
    bot.shadow = Math.min(6, bot.shadow + 1);

    this.emit("shadow_changed", {
      roomId: this.roomId,
      playerId: bot.id,
      shadow: bot.shadow,
    });

    this.emit("card_played", {
      roomId: this.roomId,
      playerId: bot.id,
      card,
      targetId: user.id,
    });

    const effect: PendingEffect = {
      id: `tutorial_effect_slash_${Date.now()}`,
      sourceId: bot.id,
      targetId: user.id,
      effectType: "draw",
      amount: 1,
    };

    this.setTutorialStep(2);

    if (!this.openReactionWindow(effect)) {
      this.resolvePendingEffect(effect);
      this.handleTutorialAfterReaction();
    }

    this.emitStateChanged();
  }

  private handleTutorialAfterReaction(): void {
    if (!this.tutorialState || this.tutorialState.completed || this.tutorialState.skipped) {
      return;
    }

    this.clearReactionWindow("resolved");

    const user = this.getPlayer(this.tutorialState.userId);
    if (!user) {
      return;
    }

    this.turnIndex = this.players.findIndex((player) => player.id === user.id);
    this.turnNumber += 1;

    this.emit("turn_started", {
      roomId: this.roomId,
      playerId: user.id,
      turnNumber: this.turnNumber,
    });

    this.setTutorialStep(3);
    this.emitStateChanged();
  }

  private playTutorialBotForgetEclipse(): void {
    if (!this.tutorialState || this.tutorialState.completed || this.tutorialState.skipped) {
      return;
    }

    const bot2 = this.getPlayer(TUTORIAL_BOT_2_ID);
    if (!bot2) {
      return;
    }

    this.turnIndex = this.players.findIndex((player) => player.id === bot2.id);

    const cardIndex = bot2.hand.findIndex((card) => card.id === TUTORIAL_BOT2_CARD_MIST2);
    if (cardIndex >= 0) {
      const [card] = bot2.hand.splice(cardIndex, 1);
      this.discardPile.push(card);
      bot2.shadow = Math.min(6, bot2.shadow + 1);

      this.emit("shadow_changed", {
        roomId: this.roomId,
        playerId: bot2.id,
        shadow: bot2.shadow,
      });

      this.emit("card_played", {
        roomId: this.roomId,
        playerId: bot2.id,
        card,
      });
    }

    if (bot2.hand.length === 1) {
      bot2.mustCallEclipse = true;
      bot2.pendingEclipsePenalty = true;
      bot2.hasCalledEclipse = false;
    }

    this.setTutorialStep(4);

    this.schedule(() => {
      this.resolveEclipsePenalty(bot2);

      const user = this.getPlayer(this.tutorialState!.userId);
      if (!user) {
        return;
      }

      this.turnIndex = this.players.findIndex((player) => player.id === user.id);
      this.turnNumber += 1;

      this.emit("turn_started", {
        roomId: this.roomId,
        playerId: user.id,
        turnNumber: this.turnNumber,
      });

      this.setTutorialStep(5);
      this.emitStateChanged();
    }, this.botDelayMs);

    this.emitStateChanged();
  }

  private setTutorialStep(index: number): void {
    if (!this.tutorialState) {
      return;
    }

    this.tutorialState.currentStepIndex = index;
    this.emitTutorialStep();
  }

  private emitTutorialStep(): void {
    if (!this.tutorialState) {
      return;
    }

    const step = TUTORIAL_STEPS[this.tutorialState.currentStepIndex];
    if (!step) {
      return;
    }

    this.emit("tutorial_step_changed", {
      roomId: this.roomId,
      stepId: step.stepId,
      message: step.message,
      allowedActions: step.allowedActions,
    });

    if (step.hintTargetUIElementId) {
      this.emit("tutorial_hint", {
        roomId: this.roomId,
        targetUIElementId: step.hintTargetUIElementId,
      });
    }
  }

  private ensureTutorialActionAllowed(playerId: string, action: string): boolean {
    if (this.roomType !== "tutorial" || !this.tutorialState) {
      return true;
    }

    if (playerId !== this.tutorialState.userId) {
      return true;
    }

    const step = TUTORIAL_STEPS[this.tutorialState.currentStepIndex];
    if (!step) {
      return false;
    }

    return step.allowedActions.includes(action);
  }

  toSnapshot(viewerId?: string): RoomSnapshot {
    const topDiscard = this.discardPile[this.discardPile.length - 1] ?? null;

    const players = this.players.map((player) => {
      const isOwner = viewerId === player.id;
      const maskedCount = this.blackout && !isOwner ? bucketCount(player.hand.length) : player.hand.length;
      return {
        id: player.id,
        name: player.name,
        isBot: player.isBot,
        ready: player.ready,
        shadow: player.shadow,
        cardCount: maskedCount,
        isCurrentTurn: this.getCurrentPlayer()?.id === player.id,
      };
    });

    const self = viewerId
      ? this.players
          .filter((player) => player.id === viewerId)
          .map((player) => ({
            id: player.id,
            hand: player.hand,
            shadow: player.shadow,
            mustCallEclipse: player.mustCallEclipse,
            hasCalledEclipse: player.hasCalledEclipse,
          }))[0]
      : undefined;

    return {
      roomId: this.roomId,
      roomType: this.roomType,
      code: this.code,
      started: this.started,
      currentPlayerId: this.getCurrentPlayer()?.id ?? null,
      direction: this.direction,
      turnNumber: this.turnNumber,
      topDiscard,
      drawPileCount: this.drawPile.length,
      players,
      self,
      reactionWindow: this.reactionWindow
        ? {
            targetId: this.reactionWindow.effect.targetId,
            effectType: this.reactionWindow.effect.effectType,
            timeoutMs: this.reactionWindow.timeoutMs,
            remainingMs: Math.max(0, this.reactionWindow.expiresAt - Date.now()),
          }
        : undefined,
      blackout: this.blackout,
      winner: this.winner,
      tutorial: this.tutorialState
        ? {
            currentStep: TUTORIAL_STEPS[this.tutorialState.currentStepIndex],
            completed: this.tutorialState.completed,
            skipped: this.tutorialState.skipped,
          }
        : undefined,
    };
  }
}
