export interface TutorialProgress {
  userId: string;
  hasCompletedTutorial: boolean;
}

export class TutorialProgressStore {
  private readonly store = new Map<string, TutorialProgress>();

  get(userId: string): TutorialProgress {
    const existing = this.store.get(userId);
    if (existing) {
      return existing;
    }

    const created: TutorialProgress = {
      userId,
      hasCompletedTutorial: false,
    };
    this.store.set(userId, created);
    return created;
  }

  markCompleted(userId: string): TutorialProgress {
    const progress = this.get(userId);
    progress.hasCompletedTutorial = true;
    this.store.set(userId, progress);
    return progress;
  }

  reset(userId: string): TutorialProgress {
    const progress = this.get(userId);
    progress.hasCompletedTutorial = false;
    this.store.set(userId, progress);
    return progress;
  }
}
