import { GameRoom } from "./room.js";
import { TutorialProgressStore } from "../store/tutorialProgressStore.js";
import type {
  Difficulty,
  EngineEvent,
  Personality,
  RoomType,
  Suit,
  RoomSnapshot,
} from "./types.js";

function makeId(prefix: string): string {
  return `${prefix}_${Math.random().toString(36).slice(2, 10)}`;
}

interface CreateRoomInput {
  hostId: string;
  hostName: string;
  socketId?: string;
  roomType?: RoomType;
}

interface JoinRoomInput {
  code: string;
  userId: string;
  userName: string;
  socketId?: string;
}

interface RoomEventEnvelope {
  roomId: string;
  event: EngineEvent;
}

export class RoomManager {
  private readonly rooms = new Map<string, GameRoom>();
  private readonly roomCodeIndex = new Map<string, string>();
  private readonly playerRoomIndex = new Map<string, string>();
  private readonly tutorialRoomByUser = new Map<string, string>();
  private readonly progressStore: TutorialProgressStore;
  private readonly onRoomEvent?: (payload: RoomEventEnvelope) => void;

  constructor(options?: {
    progressStore?: TutorialProgressStore;
    onRoomEvent?: (payload: RoomEventEnvelope) => void;
    tutorialReactionTimeoutMs?: number;
    multiplayerReactionTimeoutMs?: number;
    botDelayMs?: number;
  }) {
    this.progressStore = options?.progressStore ?? new TutorialProgressStore();
    this.onRoomEvent = options?.onRoomEvent;
    this.tutorialReactionTimeoutMs = options?.tutorialReactionTimeoutMs ?? 3000;
    this.multiplayerReactionTimeoutMs = options?.multiplayerReactionTimeoutMs ?? 7000;
    this.botDelayMs = options?.botDelayMs ?? 250;
  }

  private readonly tutorialReactionTimeoutMs: number;
  private readonly multiplayerReactionTimeoutMs: number;
  private readonly botDelayMs: number;

  private handleRoomEvent(roomId: string, event: EngineEvent): void {
    if (event.type === "tutorial_completed") {
      const userId = event.payload?.userId;
      if (typeof userId === "string") {
        this.progressStore.markCompleted(userId);
      }
    }

    this.onRoomEvent?.({ roomId, event });
  }

  private createRoom(roomType: RoomType): GameRoom {
    const roomId = makeId("room");
    const seed = Math.floor(Math.random() * 1_000_000_000);
    const room = new GameRoom({
      roomId,
      code: "",
      roomType,
      seed,
      tutorialReactionTimeoutMs: this.tutorialReactionTimeoutMs,
      multiplayerReactionTimeoutMs: this.multiplayerReactionTimeoutMs,
      botDelayMs: this.botDelayMs,
      onEmit: (event) => this.handleRoomEvent(roomId, event),
    });

    this.rooms.set(roomId, room);
    this.roomCodeIndex.set(room.code, roomId);
    return room;
  }

  createLobby(input: CreateRoomInput): { room: GameRoom; snapshot: RoomSnapshot } {
    const room = this.createRoom(input.roomType ?? "multiplayer");
    room.addPlayer({
      id: input.hostId,
      name: input.hostName,
      socketId: input.socketId,
      connected: true,
      isBot: false,
    });
    this.playerRoomIndex.set(input.hostId, room.roomId);
    return {
      room,
      snapshot: room.toSnapshot(input.hostId),
    };
  }

  getRoomByCode(code: string): GameRoom | undefined {
    const roomId = this.roomCodeIndex.get(code.toUpperCase());
    if (!roomId) {
      return undefined;
    }
    return this.rooms.get(roomId);
  }

  getRoomById(roomId: string): GameRoom | undefined {
    return this.rooms.get(roomId);
  }

  getRoomByPlayer(playerId: string): GameRoom | undefined {
    const roomId = this.playerRoomIndex.get(playerId);
    if (!roomId) {
      return undefined;
    }
    return this.rooms.get(roomId);
  }

  joinLobby(input: JoinRoomInput): { room: GameRoom; snapshot: RoomSnapshot } {
    const room = this.getRoomByCode(input.code);
    if (!room) {
      throw new Error("Room not found");
    }

    if (room.roomType !== "multiplayer") {
      throw new Error("Join is only allowed for multiplayer rooms");
    }

    room.addPlayer({
      id: input.userId,
      name: input.userName,
      socketId: input.socketId,
      connected: true,
      isBot: false,
    });

    this.playerRoomIndex.set(input.userId, room.roomId);

    return {
      room,
      snapshot: room.toSnapshot(input.userId),
    };
  }

  leaveRoom(playerId: string): void {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      return;
    }

    room.removePlayer(playerId);
    this.playerRoomIndex.delete(playerId);

    if (room.players.length === 0) {
      this.removeRoom(room.roomId);
    }
  }

  markDisconnected(playerId: string): void {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      return;
    }
    room.setPlayerConnected(playerId, false);
  }

  markConnected(playerId: string, socketId: string): void {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      return;
    }
    room.setPlayerSocket(playerId, socketId);
  }

  setReady(playerId: string, ready: boolean): RoomSnapshot {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      throw new Error("Room not found");
    }
    room.setReady(playerId, ready);
    return room.toSnapshot(playerId);
  }

  addBot(
    playerId: string,
    bot: {
      difficulty: Difficulty;
      personality: Personality;
      name?: string;
    },
  ): RoomSnapshot {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      throw new Error("Room not found");
    }

    const added = room.addBot(bot);
    this.playerRoomIndex.set(added.id, room.roomId);
    return room.toSnapshot(playerId);
  }

  startMatch(playerId: string): RoomSnapshot {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      throw new Error("Room not found");
    }

    room.start();
    return room.toSnapshot(playerId);
  }

  playCard(input: {
    playerId: string;
    cardId: string;
    targetId?: string;
    blackoutSuit?: Suit;
  }): RoomSnapshot {
    const room = this.getRoomByPlayer(input.playerId);
    if (!room) {
      throw new Error("Room not found");
    }

    room.playCard(input);
    return room.toSnapshot(input.playerId);
  }

  reaction(input: {
    playerId: string;
    cardId: string;
    redirectTargetId?: string;
  }): RoomSnapshot {
    const room = this.getRoomByPlayer(input.playerId);
    if (!room) {
      throw new Error("Room not found");
    }

    room.useReaction(input);
    return room.toSnapshot(input.playerId);
  }

  eclipseCall(playerId: string): RoomSnapshot {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      throw new Error("Room not found");
    }

    room.eclipseCall(playerId);
    return room.toSnapshot(playerId);
  }

  drawCard(playerId: string, endTurn = true): RoomSnapshot {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      throw new Error("Room not found");
    }

    room.drawForPlayer(playerId, 1, endTurn);
    return room.toSnapshot(playerId);
  }

  startTutorial(input: {
    userId: string;
    userName: string;
    socketId?: string;
  }): { room: GameRoom; snapshot: RoomSnapshot; progress: { hasCompletedTutorial: boolean } } {
    const existingRoomId = this.tutorialRoomByUser.get(input.userId);
    const existingRoom = existingRoomId ? this.rooms.get(existingRoomId) : undefined;

    if (existingRoom) {
      existingRoom.restartTutorial(input.userName);
      if (input.socketId) {
        existingRoom.setPlayerSocket(input.userId, input.socketId);
      }
      this.playerRoomIndex.set(input.userId, existingRoom.roomId);
      return {
        room: existingRoom,
        snapshot: existingRoom.toSnapshot(input.userId),
        progress: {
          hasCompletedTutorial: this.progressStore.get(input.userId).hasCompletedTutorial,
        },
      };
    }

    const room = this.createRoom("tutorial");
    room.addPlayer({
      id: input.userId,
      name: input.userName,
      socketId: input.socketId,
      connected: true,
      isBot: false,
    });
    room.start();

    this.playerRoomIndex.set(input.userId, room.roomId);
    this.tutorialRoomByUser.set(input.userId, room.roomId);

    return {
      room,
      snapshot: room.toSnapshot(input.userId),
      progress: {
        hasCompletedTutorial: this.progressStore.get(input.userId).hasCompletedTutorial,
      },
    };
  }

  restartTutorial(input: {
    userId: string;
    userName?: string;
  }): { room: GameRoom; snapshot: RoomSnapshot; progress: { hasCompletedTutorial: boolean } } {
    const roomId = this.tutorialRoomByUser.get(input.userId);
    if (!roomId) {
      throw new Error("Tutorial room not found. Start tutorial first.");
    }

    const room = this.rooms.get(roomId);
    if (!room) {
      throw new Error("Tutorial room not found");
    }

    room.restartTutorial(input.userName);

    return {
      room,
      snapshot: room.toSnapshot(input.userId),
      progress: {
        hasCompletedTutorial: this.progressStore.get(input.userId).hasCompletedTutorial,
      },
    };
  }

  skipTutorial(userId: string): RoomSnapshot {
    const roomId = this.tutorialRoomByUser.get(userId);
    if (!roomId) {
      throw new Error("Tutorial room not found");
    }

    const room = this.rooms.get(roomId);
    if (!room) {
      throw new Error("Tutorial room not found");
    }

    room.skipTutorial(userId);
    return room.toSnapshot(userId);
  }

  getTutorialProgress(userId: string): { hasCompletedTutorial: boolean } {
    return {
      hasCompletedTutorial: this.progressStore.get(userId).hasCompletedTutorial,
    };
  }

  getSnapshot(playerId: string): RoomSnapshot {
    const room = this.getRoomByPlayer(playerId);
    if (!room) {
      throw new Error("Room not found");
    }
    return room.toSnapshot(playerId);
  }

  private removeRoom(roomId: string): void {
    const room = this.rooms.get(roomId);
    if (!room) {
      return;
    }

    for (const player of room.players) {
      this.playerRoomIndex.delete(player.id);
      if (room.roomType === "tutorial" && !player.isBot) {
        this.tutorialRoomByUser.delete(player.id);
      }
    }

    this.roomCodeIndex.delete(room.code);
    room.destroy();
    this.rooms.delete(roomId);
  }
}
EOF"}

